require_once dirname(__DIR__).'/helpers.php';require_admin();header('Content-Type:text/csv;charset=utf-8');header('Content-Disposition:attachment;filename="donasi-pedulikita-'.date('Y-m-d').'.csv"');$o=fopen('php://output','w');fputs($o,"\xEF\xBB\xBF");fputcsv($o,['Kode','Tanggal','Donatur','Email','Kampanye','Nominal','Metode','Status']);$q=db()->query("SELECT d.*,c.title campaign_title FROM donations d JOIN campaigns c ON c.id=d.campaign_id ORDER BY d.created_at DESC");foreach($q as $r)fputcsv($o,[$r['receipt_code'],$r['created_at'],$r['anonymous']?'Hamba Allah':$r['donor_name'],$r['email'],$r['campaign_title'],$r['amount'],$r['payment_method'],$r['status']]);fclose($o);exit;
